-- Tạo Bài 2 "Cách đọc sơ đồ hợp âm" cho khoá "Đệm hát cơ bản", Chương 1: Hợp âm.
-- TRƯỚC KHI CHẠY: thay AUDIO_URL_HERE bằng URL file WAV/MP3 đã upload lên Supabase Storage.
-- Idempotent — chạy lại sẽ cập nhật, không tạo trùng.
DO $$
DECLARE
  v_course uuid;
  v_mod    uuid;
  v_lesson uuid;
BEGIN
  SELECT id INTO v_course FROM edu_courses WHERE name ILIKE '%Đệm hát cơ bản%' LIMIT 1;
  IF v_course IS NULL THEN RAISE EXCEPTION 'Không tìm thấy khoá "Đệm hát cơ bản"'; END IF;

  SELECT id INTO v_mod FROM edu_modules WHERE course_id = v_course AND name ILIKE 'Chương 1%' LIMIT 1;
  IF v_mod IS NULL THEN RAISE EXCEPTION 'Không tìm thấy Chương 1 trong khoá'; END IF;

  -- Bài 2
  SELECT id INTO v_lesson FROM edu_course_lessons
    WHERE module_id = v_mod AND title ILIKE 'Cách đọc sơ đồ%' LIMIT 1;
  IF v_lesson IS NULL THEN
    INSERT INTO edu_course_lessons (module_id, title, lesson_type, order_index, tools)
      VALUES (v_mod, 'Cách đọc sơ đồ hợp âm', 'flow', 1, '[]') RETURNING id INTO v_lesson;
  ELSE
    UPDATE edu_course_lessons SET lesson_type = 'flow' WHERE id = v_lesson;
  END IF;

  -- Flow
  DELETE FROM flows WHERE lesson_id = v_lesson;
  INSERT INTO flows (lesson_id, title, reward_xp, status, slides) VALUES (
    v_lesson, 'Cách đọc sơ đồ hợp âm', 15, 'published',
    $json$[
      {"id":"sd0","order":1,"logic":"DAN","type":"callout","title":"Mục tiêu","interactive":{"variant":"teacher"},"content":"Sau bài này, bạn đọc được bất kỳ sơ đồ hợp âm nào: biết đặt ngón tay ở đâu, dây nào gảy, dây nào bỏ qua."},
      {"id":"sd1","order":2,"logic":"NHAN","type":"narrated_slideshow","title":"Cách đọc sơ đồ hợp âm","interactive":{"audio_url": "AUDIO_URL_HERE", "title": "Cách đọc sơ đồ hợp âm", "slides": [{"label": "Mở bài", "html": "<div data-pop data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:380px;height:auto;overflow:visible;\">\n      <circle cx=\"40\" cy=\"42\" r=\"11\" fill=\"none\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n      <circle cx=\"172\" cy=\"42\" r=\"11\" fill=\"none\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n      <circle cx=\"216\" cy=\"42\" r=\"11\" fill=\"none\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n      <circle cx=\"260\" cy=\"42\" r=\"11\" fill=\"none\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"/>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"/>\n      <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"/>\n      <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n      <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"/>\n      <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"/>\n      <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"/>\n      <circle cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"/>\n      <text x=\"84\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\" font-family=\"'Be Vietnam Pro'\">2</text>\n      <circle cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"/>\n      <text x=\"128\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\" font-family=\"'Be Vietnam Pro'\">3</text>\n    </svg>\n  </div>\n  <div style=\"flex:none;max-width:760px;\">\n    <div data-rise data-d=\"2\" style=\"font-size:30px;font-weight:600;letter-spacing:.32em;color:#E2673B;text-transform:uppercase;margin-bottom:24px;\">Học guitar từ số 0</div>\n    <h1 data-rise data-d=\"3\" style=\"font-size:148px;line-height:.92;font-weight:900;letter-spacing:-.02em;margin:0;text-wrap:balance;\">SƠ ĐỒ<br>HỢP ÂM</h1>\n    <div data-rise data-d=\"4\" style=\"font-size:46px;font-weight:500;color:#5C564B;margin-top:36px;\">Bản đồ cho tay trái <span data-float style=\"display:inline-block;\">←</span></div>\n  </div>", "end_sec": 11.5}, {"label": "Cần đàn dựng đứng", "html": "<h2 data-rise data-d=\"1\" style=\"font-size:34px;font-weight:700;letter-spacing:.28em;color:#E2673B;text-transform:uppercase;margin:0 0 50px;\">Cần đàn dựng đứng</h2>\n  <div style=\"display:flex;align-items:center;justify-content:center;gap:80px;\">\n    <div data-rise data-d=\"2\" style=\"flex:none;\">\n      <svg viewBox=\"0 0 200 470\" style=\"width:200px;height:auto;\">\n        <rect x=\"68\" y=\"6\" width=\"64\" height=\"54\" rx=\"12\" fill=\"#3C2A1E\"/>\n        <rect x=\"54\" y=\"58\" width=\"92\" height=\"392\" rx=\"10\" fill=\"#6B4A32\"/>\n        <rect x=\"54\" y=\"58\" width=\"92\" height=\"11\" rx=\"3\" fill=\"#EFE7D6\"/>\n        <line x1=\"54\" y1=\"135\" x2=\"146\" y2=\"135\" stroke=\"#cBae8e\" stroke-width=\"2.5\" opacity=\".6\"/>\n        <line x1=\"54\" y1=\"212\" x2=\"146\" y2=\"212\" stroke=\"#cBae8e\" stroke-width=\"2.5\" opacity=\".6\"/>\n        <line x1=\"54\" y1=\"289\" x2=\"146\" y2=\"289\" stroke=\"#cBae8e\" stroke-width=\"2.5\" opacity=\".6\"/>\n        <line x1=\"54\" y1=\"366\" x2=\"146\" y2=\"366\" stroke=\"#cBae8e\" stroke-width=\"2.5\" opacity=\".6\"/>\n        <line x1=\"68\" y1=\"62\" x2=\"68\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"3.4\"/>\n        <line x1=\"82\" y1=\"62\" x2=\"82\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"3\"/>\n        <line x1=\"96\" y1=\"62\" x2=\"96\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"2.4\"/>\n        <line x1=\"110\" y1=\"62\" x2=\"110\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"2\"/>\n        <line x1=\"124\" y1=\"62\" x2=\"124\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"1.6\"/>\n        <line x1=\"138\" y1=\"62\" x2=\"138\" y2=\"448\" stroke=\"#EFE7D6\" stroke-width=\"1.3\"/>\n      </svg>\n    </div>\n    <div data-pop data-d=\"4\" style=\"flex:none;font-size:80px;font-weight:300;color:#B7AE9C;\">→</div>\n    <div data-rise data-d=\"5\" style=\"flex:none;\">\n      <svg viewBox=\"0 0 300 440\" style=\"width:260px;height:auto;\">\n        <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"/>\n        <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n        <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n        <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n        <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n        <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"/>\n        <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"/>\n        <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"/>\n        <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"/>\n        <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"/>\n        <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"/>\n      </svg>\n    </div>\n  </div>\n  <div data-rise data-d=\"6\" style=\"font-size:62px;font-weight:900;letter-spacing:-.01em;margin-top:54px;\">SƠ ĐỒ <span style=\"color:#E2673B;\">=</span> MẶT CẦN ĐÀN</div>", "end_sec": 22.4}, {"label": "6 dây đàn", "html": "<div data-rise data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:380px;height:auto;overflow:visible;\">\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"/>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line data-str=\"0\" data-pop data-d=\"1\" x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"5\"/>\n      <line data-str=\"1\" data-pop data-d=\"2\" x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"4\"/>\n      <line data-str=\"2\" data-pop data-d=\"3\" x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"3.2\"/>\n      <line data-str=\"3\" data-pop data-d=\"4\" x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"2.6\"/>\n      <line data-str=\"4\" data-pop data-d=\"5\" x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"2\"/>\n      <line data-str=\"5\" data-pop data-d=\"6\" x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"1.5\"/>\n    </svg>\n  </div>\n  <div style=\"flex:none;max-width:680px;\">\n    <div data-rise data-d=\"6\" style=\"font-size:120px;font-weight:900;line-height:.9;letter-spacing:-.02em;\">6 DÂY<br>ĐÀN</div>\n    <div data-rise data-d=\"7\" style=\"display:flex;align-items:center;gap:18px;margin-top:46px;font-size:40px;font-weight:600;color:#5C564B;\">\n      <span style=\"font-size:54px;font-weight:800;color:#1C1B1