anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#E2673B\" font-family=\"'Be Vietnam Pro'\">2</text>\n      <text data-pop data-d=\"4\" x=\"22\" y=\"280\" text-anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#E2673B\" font-family=\"'Be Vietnam Pro'\">3</text>\n    </svg>\n  </div>\n  <div style=\"flex:none;max-width:680px;\">\n    <div data-rise data-d=\"5\" style=\"font-size:84px;font-weight:900;line-height:.9;letter-spacing:-.02em;\">ĐƯỜNG<br>NGANG</div>\n    <div data-rise data-d=\"6\" style=\"font-size:50px;font-weight:600;color:#E2673B;margin-top:30px;\">= NGĂN ĐÀN</div>\n    <div style=\"display:flex;gap:16px;margin-top:48px;\">\n      <div data-pop data-d=\"5\" style=\"width:96px;height:96px;border-radius:18px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:46px;font-weight:800;\">1</div>\n      <div data-pop data-d=\"6\" style=\"width:96px;height:96px;border-radius:18px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:46px;font-weight:800;\">2</div>\n      <div data-pop data-d=\"7\" style=\"width:96px;height:96px;border-radius:18px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:46px;font-weight:800;\">3</div>\n    </div>\n  </div>", "end_sec": 49.1}, {"label": "Chấm đen", "html": "<div data-rise data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:380px;height:auto;overflow:visible;\">\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"/>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"/>\n      <line x1=\